  1→// Package setup provides setup file loading and context management for the
  2→// Go frontend. Setup files are compiled and run as subprocesses; their JSON
  3→// stdout output becomes the opaque setup_context returned to the core engine.
  4→package setup
  5→
  6→import (
  7→	"encoding/json"
  8→	"fmt"
  9→	"os"
 10→	"os/exec"
 11→	"path/filepath"
 12→	"sync"
 13→)
 14→
 15→// contextKey uniquely identifies a setup context by scope and level.
 16→type contextKey struct {
 17→	Scope string
 18→	Level string
 19→}
 20→
 21→// Loader compiles and runs Go setup files, caching their contexts by
 22→// (scope, level) for later teardown.
 23→type Loader struct {
 24→	mu       sync.Mutex
 25→	contexts map[contextKey]json.RawMessage
 26→}
 27→
 28→// NewLoader creates a Loader with an empty context cache.
 29→func NewLoader() *Loader {
 30→	return &Loader{
 31→		contexts: make(map[contextKey]json.RawMessage),
 32→	}
 33→}
 34→
 35→// RunSetup compiles and executes the setup file, returning the opaque context.
 36→// The setup file must be a valid Go source file with a main function that
 37→// prints a single JSON object to stdout. Environment variables are set to
 38→// communicate scope, level, and parent context to the setup process.
 39→func (l *Loader) RunSetup(file, scope, level string, projectRoot *string, parentContext json.RawMessage) (json.RawMessage, error) {
 40→	absFile, err := filepath.Abs(file)
 41→	if err != nil {
 42→		return nil, fmt.Errorf("resolving setup file path: %w", err)
 43→	}
 44→	if _, err := os.Stat(absFile); err != nil {
 45→		return nil, fmt.Errorf("setup file not found: %s", absFile)
 46→	}
 47→
 48→	// Build the setup file to a temporary binary.
 49→	tmpDir, err := os.MkdirTemp("", "shatter-setup-*")
 50→	if err != nil {
 51→		return nil, fmt.Errorf("creating temp dir: %w", err)
 52→	}
 53→	defer os.RemoveAll(tmpDir)
 54→
 55→	binPath := filepath.Join(tmpDir, "setup")
 56→	buildCmd := exec.Command("go", "build", "-o", binPath, absFile)
 57→	buildCmd.Dir = filepath.Dir(absFile)
 58→	if out, err := buildCmd.CombinedOutput(); err != nil {
 59→		return nil, fmt.Errorf("building setup file: %s: %w", string(out), err)
 60→	}
 61→
 62→	// Run the compiled setup binary.
 63→	runCmd := exec.Command(binPath)
 64→	runCmd.Dir = filepath.Dir(absFile)
 65→	runCmd.Env = append(os.Environ(),
 66→		"SHATTER_SETUP_SCOPE="+scope,
 67→		"SHATTER_SETUP_LEVEL="+level,
 68→	)
 69→	if projectRoot != nil {
 70→		runCmd.Env = append(runCmd.Env, "SHATTER_PROJECT_ROOT="+*projectRoot)
 71→	}
 72→	if len(parentContext) > 0 {
 73→		runCmd.Env = append(runCmd.Env, "SHATTER_PARENT_CONTEXT="+string(parentContext))
 74→	}
 75→
 76→	stdout, err := runCmd.Output()
 77→	if err != nil {
 78→		if exitErr, ok := err.(*exec.ExitError); ok {
 79→			return nil, fmt.Errorf("setup file exited with error: %s: %s", exitErr, string(exitErr.Stderr))
 80→		}
 81→		return nil, fmt.Errorf("running setup file: %w", err)
 82→	}
 83→
 84→	// Validate that the output is valid JSON.
 85→	stdout = trimTrailingNewlines(stdout)
 86→	if len(stdout) == 0 {
 87→		// No output — use empty object as context.
 88→		stdout = []byte("{}")
 89→	}
 90→	if !json.Valid(stdout) {
 91→		return nil, fmt.Errorf("setup file output is not valid JSON: %s", string(stdout))
 92→	}
 93→
 94→	ctx := json.RawMessage(stdout)
 95→
 96→	// Cache the context.
 97→	l.mu.Lock()
 98→	l.contexts[contextKey{Scope: scope, Level: level}] = ctx
 99→	l.mu.Unlock()
100→
101→	return ctx, nil
102→}
103→
104→// Teardown removes the cached context for the given scope and level.
105→// Returns true if a context was found and removed, false otherwise.
106→func (l *Loader) Teardown(scope, level string) bool {
107→	l.mu.Lock()
108→	defer l.mu.Unlock()
109→	key := contextKey{Scope: scope, Level: level}
110→	_, found := l.contexts[key]
111→	delete(l.contexts, key)
112→	return found
113→}
114→
115→// GetContext returns the cached context for the given scope and level, if any.
116→func (l *Loader) GetContext(scope, level string) (json.RawMessage, bool) {
117→	l.mu.Lock()
118→	defer l.mu.Unlock()
119→	ctx, ok := l.contexts[contextKey{Scope: scope, Level: level}]
120→	return ctx, ok
121→}
122→
123→// Close clears all cached contexts.
124→func (l *Loader) Close() {
125→	l.mu.Lock()
126→	defer l.mu.Unlock()
127→	l.contexts = make(map[contextKey]json.RawMessage)
128→}
